import React from 'react';
import './Research.css';

import { Container, Row } from 'react-bootstrap';
import { sectionHeader, listSomething } from '../utils/Utils';
import papers from '../../data/Publications';
import awards from '../../data/Awards';

class Research extends React.Component {

  render() {
    return (
        <div>
            {papers.length > 0 && 
                <Container className="publications">
                    { sectionHeader("📋", "Publications", "Currently my research topics are computer vision and imitation learning.") }
                    <Row>
                        { listSomething(papers) }
                    </Row>
                </Container>
            }
            { awards.length > 0 && 
                <Container className="awards">
                    { sectionHeader("🏆", "Awards", null) }
                    <Row>
                        { listSomething(awards) }
                    </Row>
                </Container>
            }
        </div>
    );
  }
}

export default Research;
